arguments.file_text:
#:property AllowUnsafeBlocks=true

Console.WriteLine("=== stackalloc Span<nint> test ===");

Span<nint> nints = stackalloc nint[5];
for (int i = 0; i < nints.Length; i++)
    nints[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {nints.Length}");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  nints[{i}] = {nints[i]}");

Console.WriteLine();
Console.WriteLine("=== stackalloc Span<nuint> test ===");

Span<nuint> nuints = stackalloc nuint[3];
for (int i = 0; i < nuints.Length; i++)
    nuints[i] = (nuint)(i + 100);

Console.WriteLine($"Span<nuint> length: {nuints.Length}");
for (int i = 0; i < nuints.Length; i++)
    Console.WriteLine($"  nuints[{i}] = {nuints[i]}");

Console.WriteLine();
Console.WriteLine($"nint size: {nint.Size} bytes (IntPtr.Size: {IntPtr.Size})");

